const express = require('express');
const { Strategy } = require('passport-openidconnect');
const passport = require('passport');
const jwt = require('jsonwebtoken');

const app = express();

app.use(passport.initialize());
app.use(passport.session());

passport.use(new Strategy({
    issuer: 'https://your-oidc-provider.com',
    authorizationURL: 'https://your-oidc-provider.com/oauth2/auth',
    tokenURL: 'https://your-oidc-provider.com/oauth2/token',
    callbackURL: 'http://localhost:3000/callback',
    clientID: 'your-client-id',
    clientSecret: 'your-client-secret'
  },
  (iss, sub, profile, accessToken, refreshToken, params, done) => {
    // Save user information in the session
    return done(null, { id: sub, email: profile.emails[0].value });
  }
));

passport.serializeUser((user, done) => {
  done(null, user.id);
});

passport.deserializeUser(async (id, done) => {
  try {
    const user = await User.findById(id); // Assuming you have a User model
    return done(null, user);
  } catch (err) {
    return done(err);
  }
});

app.get('/login', passport.authenticate('openidconnect'));

app.get('/callback',
  passport.authenticate('openidconnect', { failureRedirect: '/login' }),
  (req, res) => {
    // Handle successful authentication
    const idToken = req.session.passport.user.id;
    try {
      const decoded = jwt.decode(idToken);
      console.log(decoded);
      // Create user session based on the decoded claims
      req.login(decoded, err => {
        if (err) return res.status(500).send(err);
        res.redirect('/profile');
      });
    } catch (error) {
      res.status(401).send('Invalid ID token');
    }
  });

app.get('/profile', (req, res) => {
  if (!req.isAuthenticated()) return res.redirect('/login');
  res.send(`Welcome, ${req.user.name}!`);
});

app.listen(3000, () => {
  console.log('Server started on http://localhost:3000');
});